mapper.insert:
/** CmmtTermsDao.insert */
insert into cmmt_terms (
	 terms_type
	,begin_day
	,required
	,terms_cn
	,possess_term_cd
	,creator_id
	,created_dt
	,updater_id
	,updated_dt
) values (
	 #{termsType}
	,#{beginDay}
	,#{required}
	,#{termsCn}
	,#{possessTermCd}
	,#{creatorId}
	,#{createdDt}
	,#{updaterId}
	,#{updatedDt}
)

mapper.select:
/** CmmtTermsDao.selectList_beginDay */ select distinct terms_type ,fn_cmm_get_code_nm('TERMS_TYPE', terms_type) as terms_type_nm ,begin_day from cmmt_terms where terms_type = #{termsType}
and begin_day = (select max(begin_day) from cmmt_terms where terms_type=#{termsType} and begin_day <= to_char(now(), 'yyyymmdd'))
order by begin_day desc

mapper.update:
/** CmmtTermsDao.update */
update cmmt_terms set
	 terms_cn   = #{termsCn}
	,possess_term_cd = #{possessTermCd}
	,creator_id = #{creatorId}
	,created_dt = #{createdDt}
	,updater_id = #{updaterId}
	,updated_dt = #{updatedDt}
where
	terms_type = #{termsType}
	and begin_day = #{beginDay}
	and required   = #{required}

mapper.delete:
/** CmmtTermsDao.delete */
delete from cmmt_terms
where
	terms_type = #{termsType}
	and begin_day = #{beginDay}
